import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.stream.ActorMaterializer
import scala.concurrent.Future

object UrlFetcher extends App {
  implicit val system = ActorSystem("url-fetcher")
  implicit val materializer = ActorMaterializer()
  implicit val executionContext = system.dispatcher

  val route = akka.http.scaladsl.server.Route {
    case POST(Entity(`application/json`, data)) =>
      import io.circe._
      import io.circe.parser._
      parse(data).flatMap { json =>
        json.hcursor.get[String]("url").toFuture().map { url =>
          Http().singleRequest(HttpRequest(uri = Uri(url)))
